// Before Java 8
list.sort(new Comparator<String>() {
    public int compare(String a, String b) { return a.compareTo(b); }
});

// Java 8 lambda
list.sort((a, b) -> a.compareTo(b));

// Method reference
list.sort(String::compareTo);

// Stream pipeline
long count = list.stream()
    .filter(s -> s.startsWith("A"))
    .map(String::toUpperCase)
    .count();

// module-info.java
module com.myapp.core {
    requires java.net.http;       // explicit dependency
    requires com.google.gson;
    exports com.myapp.api;        // only this package visible to other modules
    // com.myapp.internal stays hidden
}

// List.of / Map.of factory methods
List<String> immutable = List.of("a", "b", "c");
Map<String, Integer> scores = Map.of("Alice", 95, "Bob", 87);

// Without var
Map<String, List<Integer>> map = new HashMap<String, List<Integer>>();

// With var — compiler infers Map<String, List<Integer>>
var map = new HashMap<String, List<Integer>>();

// In for-each
for (var entry : map.entrySet()) {
    System.out.println(entry.getKey() + ": " + entry.getValue());
}

// NOT allowed: var for fields, method params, or return types

HttpClient client = HttpClient.newBuilder()
    .connectTimeout(Duration.ofSeconds(10))
    .build();

HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://api.example.com/users"))
    .header("Accept", "application/json")
    .GET()
    .build();

// Synchronous
HttpResponse<String> response =
    client.send(request, BodyHandlers.ofString());
System.out.println(response.statusCode()); // 200

// Async
client.sendAsync(request, BodyHandlers.ofString())
    .thenApply(HttpResponse::body)
    .thenAccept(System.out::println);

// Old switch statement (fall-through risk)
int numLetters;
switch (day) {
    case MONDAY: case FRIDAY: case SUNDAY: numLetters = 6; break;
    case TUESDAY: numLetters = 7; break;
    default: numLetters = 9;
}

// New switch expression — exhaustive, no fall-through
int numLetters = switch (day) {
    case MONDAY, FRIDAY, SUNDAY -> 6;
    case TUESDAY                -> 7;
    case THURSDAY, SATURDAY     -> 8;
    case WEDNESDAY              -> 9;
};

// With yield for multi-statement arms
String result = switch (status) {
    case OK -> "Success";
    case ERROR -> {
        log.warn("error");
        yield "Failed";
    }
};

