// Record declaration — 1 line!
record Point(int x, int y) {}

// Compiler generates:
// - canonical constructor Point(int x, int y)
// - accessors: point.x(), point.y()
// - equals, hashCode, toString

Point p = new Point(3, 4);
System.out.println(p.x());    // 3
System.out.println(p);        // Point[x=3, y=4]

// Custom validation in compact constructor
record Range(int lo, int hi) {
    Range {
        if (lo > hi) throw new IllegalArgumentException(lo + " > " + hi);
    }
}

// Generic record
record Pair<A, B>(A first, B second) {}

// Before Java 16
if (obj instanceof String) {
    String s = (String) obj; // redundant cast
    System.out.println(s.length());
}

// Java 16+
if (obj instanceof String s) {
    System.out.println(s.length()); // s is String, no cast needed
}

// Combines naturally with &&
if (obj instanceof Integer i && i > 0) {
    System.out.println("Positive: " + i);
}

// Sealed interface — only these 3 types can implement it
sealed interface Shape permits Circle, Rectangle, Triangle {}

record Circle(double radius) implements Shape {}
record Rectangle(double w, double h) implements Shape {}
final class Triangle implements Shape { /* ... */ }

// Compiler knows all cases — switch is exhaustive
double area = switch (shape) {
    case Circle c    -> Math.PI * c.radius() * c.radius();
    case Rectangle r -> r.w() * r.h();
    case Triangle t  -> /* ... */ 0;
    // No default needed — compiler verifies exhaustiveness!
};

// Create 100,000 virtual threads — no problem!
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    IntStream.range(0, 100_000).forEach(i -> executor.submit(() -> {
        Thread.sleep(Duration.ofSeconds(1)); // doesn't block OS thread!
        return i * 2;
    }));
} // waits for all tasks

// Direct creation
Thread vt = Thread.ofVirtual().name("worker").start(() -> {
    System.out.println("Running on: " + Thread.currentThread());
});

// Production-ready: one virtual thread per request (Spring Boot 3.2+ default)
try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
    List<Future<String>> results = IntStream.range(0, 10_000)
        .mapToObj(i -> executor.submit(() -> fetchUser(i)))
        .toList();
    // 10,000 concurrent HTTP calls with blocking code!
}

// Spring Boot — just set in application.properties:
// spring.threads.virtual.enabled=true
// No code changes needed — Tomcat uses virtual threads automatically

// Key rule: avoid synchronized blocks with long I/O
// (pins the carrier thread) — use ReentrantLock instead
var lock = new ReentrantLock();
lock.lock();
try { /* safe with virtual threads */ } finally { lock.unlock(); }

record Point(int x, int y) {}
record Line(Point from, Point to) {}

// Record pattern — destructure components
Object obj = new Point(3, 4);
if (obj instanceof Point(int x, int y)) {
    System.out.println("x=" + x + ", y=" + y);
}

// Nested record patterns
if (line instanceof Line(Point(int x1, int y1), Point(int x2, int y2))) {
    double length = Math.hypot(x2 - x1, y2 - y1);
}

// In switch
double area = switch (shape) {
    case Circle(double r)       -> Math.PI * r * r;
    case Rectangle(double w, double h) -> w * h;
};

sealed interface Expr permits Num, Add, Mul {}
record Num(int value) implements Expr {}
record Add(Expr left, Expr right) implements Expr {}
record Mul(Expr left, Expr right) implements Expr {}

int eval(Expr expr) {
    return switch (expr) {
        case Num(int v)         -> v;
        case Add(var l, var r)  -> eval(l) + eval(r);
        case Mul(var l, var r)  -> eval(l) * eval(r);
        // No default — sealed hierarchy is exhaustive!
    };
}

// Guarded patterns with when
String classify(Object obj) {
    return switch (obj) {
        case Integer i when i < 0 -> "negative";
        case Integer i            -> "non-negative integer";
        case String s when s.isBlank() -> "blank string";
        case String s             -> "string: " + s;
        case null                 -> "null";
        default                   -> "other";
    };
}

// Before Java 21 — different idioms for first/last
list.get(0);                          // List
deque.peekFirst();                    // Deque  
linkedHashSet.iterator().next();      // Set — awkward!

// Java 21 — uniform SequencedCollection API
list.getFirst();          // List (new method)
list.getLast();           // List (new method)
deque.getFirst();         // Deque
set.getFirst();           // LinkedHashSet — now works!

// Reversed view (live, not a copy)
List<Integer> nums = new ArrayList<>(List.of(1, 2, 3));
List<Integer> rev = nums.reversed(); // [3, 2, 1]

// SequencedMap: firstEntry(), lastEntry(), reversed()
LinkedHashMap<String, Integer> map = new LinkedHashMap<>();
map.put("a", 1); map.put("b", 2);
System.out.println(map.firstEntry()); // a=1
System.out.println(map.lastEntry());  // b=2
